import{_ as t,a as o,b as a,c as d,d as r}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as i}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as c,o as n,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const C=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/Other/ocr.md","filePath":"bn-BD/Other/ocr.md","lastUpdated":1781962217000}'),p={name:"bn-BD/Other/ocr.md"};function u(h,e,g,m,b,y){return n(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR images, scans এবং document screenshots থেকে text extract করে।</p><p>Recognition-এর পর result copy করা যায়, <code>Markdown</code>, <code>PDF</code> বা <code>Word</code> হিসেবে export করা যায়, অথবা multiple formats একসঙ্গে package করে download করা যায়।</p><h2 id="ocr-কী-করতে-পারে" tabindex="-1">OCR কী করতে পারে <a class="header-anchor" href="#ocr-কী-করতে-পারে" aria-label="Permalink to &quot;OCR কী করতে পারে&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Image text recognition</td><td>Images, screenshots এবং scans থেকে text extract করে।</td></tr><tr><td>Document layout recognition</td><td>Tables, formulas, stamps এবং mixed text-image layouts-এর জন্য ভালো।</td></tr><tr><td>Multiple services</td><td>Baidu PaddleOCR, Microsoft Azure Vision এবং Google Vision support করে।</td></tr><tr><td>Copy results</td><td>Processing-এর পর recognized text copy করুন।</td></tr><tr><td>Export files</td><td><code>Markdown</code>, <code>PDF</code> এবং <code>Word</code> export করুন।</td></tr><tr><td>Batch packaging</td><td>Multiple files recognize করার পর results package হিসেবে download করুন।</td></tr></tbody></table><h2 id="আগে-ocr-services-configure-করুন" tabindex="-1">আগে OCR Services Configure করুন <a class="header-anchor" href="#আগে-ocr-services-configure-করুন" aria-label="Permalink to &quot;আগে OCR Services Configure করুন&quot;">​</a></h2><p>খুলুন:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+t+'" alt="IP geolocation and OCR" loading="lazy"></p><p>যে services ব্যবহার করতে চান সেগুলোর credentials পূরণ করুন:</p><table tabindex="0"><thead><tr><th>Service</th><th>What To Enter</th><th>Best For</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>Recommended first choice। Documents, images, tables এবং mixed layouts-এর জন্য ভালো।</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> এবং <code>Azure Vision API Key</code></td><td>Microsoft cloud services ব্যবহার করলে useful।</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>। Service account <code>JSON</code> শুধু quota query-এর জন্য।</td><td>Google Cloud services ব্যবহার করলে useful।</td></tr></tbody></table><p>Credentials পূরণ করার পর save করুন।</p><p>Initial testing-এর জন্য একটি service configure করলেই হয়। তিনটিই দরকার নেই।</p><h2 id="google-vision-setup" tabindex="-1">Google Vision Setup <a class="header-anchor" href="#google-vision-setup" aria-label="Permalink to &quot;Google Vision Setup&quot;">​</a></h2><p>Google setup-এর দুটি অংশ:</p><table tabindex="0"><thead><tr><th>Goal</th><th>Requirement</th></tr></thead><tbody><tr><td>OCR ব্যবহার</td><td><code>Cloud Vision API</code> enable করুন, তারপর <code>API Key</code> তৈরি করুন।</td></tr><tr><td>Usage query</td><td>Service account তৈরি করুন, <code>Monitoring Viewer</code> grant করুন, তারপর service account <code>JSON</code> download করুন।</td></tr></tbody></table><p><img src="'+i+'" alt="Google API key and service account" loading="lazy"></p><h3 id="ocr-এর-জন্য-google-ব্যবহার" tabindex="-1">OCR-এর জন্য Google ব্যবহার <a class="header-anchor" href="#ocr-এর-জন্য-google-ব্যবহার" aria-label="Permalink to &quot;OCR-এর জন্য Google ব্যবহার&quot;">​</a></h3><ol><li>Google Cloud Console খুলুন।</li><li><code>APIs &amp; Services</code>-এ যান।</li><li><code>Library</code> খুলে <code>Cloud Vision API</code> search করে enable করুন।</li><li><code>Credentials</code>-এ ফিরে যান।</li><li>একটি <code>API Key</code> তৈরি করুন।</li><li>API Key খুলে copy করুন।</li><li>ImgBed-এর <code>Google Vision API Key</code>-এ paste করুন।</li><li>Save করুন।</li></ol><p>এরপর OCR dialog-এ Google Vision নির্বাচন করতে পারবেন।</p><h3 id="google-usage-query" tabindex="-1">Google Usage Query <a class="header-anchor" href="#google-usage-query" aria-label="Permalink to &quot;Google Usage Query&quot;">​</a></h3><p>Quota query recognition-এর জন্য required নয়।</p><p>এটি শুধু গত 30 দিনে কত Google Vision calls ব্যবহৃত হয়েছে তার rough count দেখায়।</p><ol><li>Google Cloud Console-এ <code>IAM &amp; Admin</code> খুলুন।</li><li><code>Service Accounts</code> খুলুন।</li><li>একটি service account তৈরি করুন, যেমন <code>vision-monitor</code>।</li><li>এটিকে <code>Monitoring Viewer</code> role দিন।</li><li>Service account details খুলে key create করুন।</li><li><code>JSON</code> নির্বাচন করুন।</li><li>Generated JSON file download করুন।</li><li>ImgBed-এ ফিরে service account <code>JSON</code>-এর নিচে import করুন (optional)।</li><li>Import successful হলে quota query ক্লিক করুন।</li></ol><p>Import-এর পর ImgBed service account-এর project name দেখায়। Usage query করার সময় ImgBed Google monitoring data পড়ে এই মাসের call count দেখায়।</p><p>সংক্ষেপে:</p><table tabindex="0"><thead><tr><th>Item</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>OCR recognition করে।</td></tr><tr><td>Service account <code>JSON</code></td><td>কত Google Vision calls ব্যবহৃত হয়েছে query করে।</td></tr><tr><td><code>Monitoring Viewer</code> role</td><td>Service account-কে usage data পড়তে দেয়।</td></tr></tbody></table><h2 id="baidu-paddleocr-token-নেওয়া" tabindex="-1">Baidu PaddleOCR Token নেওয়া <a class="header-anchor" href="#baidu-paddleocr-token-নেওয়া" aria-label="Permalink to &quot;Baidu PaddleOCR Token নেওয়া&quot;">​</a></h2><p>Baidu PaddleOCR access token চায়।</p><p><img src="'+o+'" alt="Get PaddleOCR token" loading="lazy"></p><p>Baidu PaddleOCR page-এর <code>API</code> call window খুলে token নেওয়ার জন্য click করুন, তারপর copy করুন।</p><p>ImgBed-এ ফিরে <code>PaddleOCR Token</code>-এ paste করে save করুন।</p><h2 id="recognition-শুরু-করা" tabindex="-1">Recognition শুরু করা <a class="header-anchor" href="#recognition-শুরু-করা" aria-label="Permalink to &quot;Recognition শুরু করা&quot;">​</a></h2><p>File Management-এ image বা document screenshot নির্বাচন করে <code>OCR</code> ক্লিক করুন।</p><p><img src="'+a+'" alt="OCR recognition" loading="lazy"></p><p>Dialog-এ recognition service এবং model নির্বাচন করুন।</p><p>Common PaddleOCR model choices:</p><table tabindex="0"><thead><tr><th>Model</th><th>Best For</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>Recommended default। Documents, tables, formulas, stamps এবং mixed layouts-এর জন্য ভালো।</td></tr><tr><td><code>PP-OCRv5</code></td><td>Simple images, ordinary text এবং lightweight recognition।</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>Multilingual, complex images এবং chart-like content।</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>আরও complex document pages এবং layout recovery।</td></tr></tbody></table><p>নিশ্চিত না হলে <code>PP-StructureV3</code> দিয়ে শুরু করুন।</p><h2 id="advanced-options" tabindex="-1">Advanced Options <a class="header-anchor" href="#advanced-options" aria-label="Permalink to &quot;Advanced Options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td>Orientation correction</td><td>Image rotated বা skewed হলে ব্যবহার করুন।</td></tr><tr><td>Document flattening</td><td>Curvature বা tilt থাকা photographed documents-এর জন্য ব্যবহার করুন।</td></tr><tr><td>Layout detection</td><td>Headings, paragraphs, tables এবং image structure preserve করতে চাইলে ব্যবহার করুন।</td></tr><tr><td>Chart recognition</td><td>Image-এ charts বা complex structures থাকলে ব্যবহার করুন।</td></tr><tr><td>Beautify <code>Markdown</code></td><td>Exported Markdown পড়তে সহজ করে।</td></tr></tbody></table><p>Regular screenshots-এর জন্য options minimal রাখুন। Document scans-এর জন্য document-related options বেশি enable করুন।</p><h2 id="results-দেখা" tabindex="-1">Results দেখা <a class="header-anchor" href="#results-দেখা" aria-label="Permalink to &quot;Results দেখা&quot;">​</a></h2><p>Recognition শেষ হলে dialog result দেখায়।</p><p>আপনি direct copy করতে পারেন বা export formats বেছে নিতে পারেন।</p><p><img src="'+d+'" alt="PDF recognition" loading="lazy"></p><p>Document pages-এর জন্য exported <code>PDF</code> page appearance preserve করতে পারে এবং text searchable রাখে। Scans archive করা এবং পরে content খোঁজার জন্য useful।</p><h2 id="export-format-নির্বাচন" tabindex="-1">Export Format নির্বাচন <a class="header-anchor" href="#export-format-নির্বাচন" aria-label="Permalink to &quot;Export Format নির্বাচন&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Best For</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>Notes, documentation systems এবং পরের editing।</td></tr><tr><td><code>PDF (.pdf)</code></td><td>Page appearance এবং scanned document results preserve করা।</td></tr><tr><td><code>Word (.docx)</code></td><td>Layout editing, text modification এবং অন্যদের handoff।</td></tr><tr><td>Export all</td><td>Multiple formats এবং original image save করে; important archives-এর জন্য suitable।</td></tr></tbody></table><p>শুধু text দরকার হলে Markdown export করুন।</p><p>Page appearance দরকার হলে PDF বা Word ব্যবহার করুন।</p><h2 id="word-output" tabindex="-1">Word Output <a class="header-anchor" href="#word-output" aria-label="Permalink to &quot;Word Output&quot;">​</a></h2><p>Exported Word documents office software দিয়ে খোলা এবং edit করা যায়।</p><p><img src="'+r+`" alt="Word result" loading="lazy"></p><p>কিছু documents-এর Word output-এ recognized images, headings এবং paragraphs থাকে।</p><p>Recognition quality original image clarity, model choice এবং document complexity-এর ওপর depend করে।</p><h2 id="ocr-এর-জন্য-ভালো-file-types" tabindex="-1">OCR-এর জন্য ভালো File Types <a class="header-anchor" href="#ocr-এর-জন্য-ভালো-file-types" aria-label="Permalink to &quot;OCR-এর জন্য ভালো File Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File Type</th><th>Recommendation</th></tr></thead><tbody><tr><td>Clear screenshots</td><td>Direct recognize করুন।</td></tr><tr><td>Scans</td><td><code>PP-StructureV3</code> prefer করুন।</td></tr><tr><td>Photographed documents</td><td>Orientation correction এবং document flattening enable করুন।</td></tr><tr><td>Tables, formulas, stamps</td><td>Structured models prefer করুন।</td></tr><tr><td>Simple short text images</td><td><code>PP-OCRv5</code> সাধারণত যথেষ্ট।</td></tr></tbody></table><p>Straight text থাকা clearer images সাধারণত ভালো results দেয়।</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Recognition fails</td><td>Service token বা key save আছে কি না check করুন।</td></tr><tr><td>Recognition slow</td><td>Complex documents এবং large images বেশি সময় নেয়।</td></tr><tr><td>Table incomplete</td><td>Structured model try করুন।</td></tr><tr><td>Text mistakes</td><td>Blur, glare এবং skew recognition errors বাড়ায়। Clearer image try করুন।</td></tr><tr><td>Word output-এ অনেক images</td><td>Structured models কিছু recognized images preserve করতে পারে। এটি normal।</td></tr></tbody></table><h3 id="google-quota-query-fail-হলে" tabindex="-1">Google Quota Query fail হলে <a class="header-anchor" href="#google-quota-query-fail-হলে" aria-label="Permalink to &quot;Google Quota Query fail হলে&quot;">​</a></h3><p>Check করুন:</p><ol><li>Service account <code>JSON</code> import হয়েছে।</li><li>Service account-এর <code>Monitoring Viewer</code> role আছে।</li><li>Project-এ <code>Cloud Vision API</code> enabled।</li></ol><p>শুধু OCR দরকার হলে usage query না করেও চলে; service account JSON ignore করে শুধু <code>Google Vision API Key</code> পূরণ করতে পারেন।</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings খুলুন</span></span>
<span class="line"><span>-&gt; Other Settings খুলুন</span></span>
<span class="line"><span>-&gt; OCR service credentials পূরণ করুন</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; File Management-এ ফিরে যান</span></span>
<span class="line"><span>-&gt; File select করে OCR ক্লিক করুন</span></span>
<span class="line"><span>-&gt; Model নির্বাচন করুন</span></span>
<span class="line"><span>-&gt; Recognition শেষ হওয়ার অপেক্ষা করুন</span></span>
<span class="line"><span>-&gt; Results copy করুন বা Markdown / PDF / Word export করুন</span></span></code></pre></div>`,67)])])}const v=c(p,[["render",u]]);export{C as __pageData,v as default};
